#!/usr/bin/env bash
# secrets-guard.sh — PreToolUse[Bash] hook (generated by scaffold-generate; placeholder-only).
# Acts ONLY on `git commit` commands: scans the STAGED diff for secrets before the commit lands.
#   - gitleaks installed  => `gitleaks protect --staged` — BLOCKING on findings.
#   - gitleaks absent     => warn-only regex fallback on a few high-signal patterns (never blocks).
# TDD fixtures are false-positive-heavy by nature: add a finding's fingerprint to .gitleaksignore
# (seeded at generation) and re-commit — never weaken the hook itself.
# Exit 2 blocks; stderr reaches the agent.

set -euo pipefail
command -v jq >/dev/null 2>&1 || exit 0

payload=$(cat)
# `|| true`: a malformed/non-JSON payload makes jq exit non-zero, which — being the last command in this
# assignment — would trip `set -e` and kill the guard before it ever runs its checks. Fail open to "no
# command" (never fail closed into silently not guarding) rather than crash.
cmd=$(printf '%s' "$payload" | jq -r '.tool_input.command // empty' 2>/dev/null) || true
printf '%s' "$cmd" | grep -qE '(^|[^a-z])git[^|;&]*[[:space:]]commit\b' || exit 0

# Project-root resolution: {{PROJECT_DIR_ENV}} is real for Claude (CLAUDE_PROJECT_DIR) but Codex sets no
# such variable under any build — Codex instead passes cwd via the hook payload's own `cwd` field. Try, in
# order: the host env var (real for Claude; unset no-op for Codex) -> the payload's `.cwd` field (real,
# documented Codex field) -> `git rev-parse --show-toplevel` (Codex's own recommended fallback so this
# still resolves correctly if codex was invoked from a subdirectory) -> `.` as a last resort.
project_dir="${{{PROJECT_DIR_ENV}}:-}"
[ -n "$project_dir" ] || project_dir=$(printf '%s' "$payload" | jq -r '.cwd // empty' 2>/dev/null) || true
[ -n "$project_dir" ] || project_dir=$(git rev-parse --show-toplevel 2>/dev/null) || true
cd "${project_dir:-.}" 2>/dev/null || exit 0

if command -v gitleaks >/dev/null 2>&1; then
  if ! out=$(gitleaks protect --staged --no-banner --redact 2>&1); then
    {
      echo "BLOCKED (secrets-guard): gitleaks found potential secrets in the staged diff:"
      printf '%s\n' "$out" | tail -15
      echo "False positive (e.g. a TDD fixture)? Add the finding's fingerprint to .gitleaksignore and re-commit. Real secret? Unstage it, rotate it, and load it from the environment instead."
    } >&2
    exit 2
  fi
else
  hits=$(git diff --staged -U0 2>/dev/null | grep -E '^\+' | grep -cE 'AKIA[0-9A-Z]{16}|-----BEGIN [A-Z ]*PRIVATE KEY-----|ghp_[A-Za-z0-9]{36}|github_pat_[A-Za-z0-9_]{20,}|xox[baprs]-[A-Za-z0-9-]{10,}|sk-[A-Za-z0-9_-]{20,}|AIza[0-9A-Za-z_-]{35}' || true)
  if [ "${hits:-0}" -gt 0 ]; then
    echo "WARN (secrets-guard): $hits staged line(s) match common secret patterns. gitleaks is not installed, so this is warn-only — review the staged diff before committing (install gitleaks to make this scan blocking)." >&2
  fi
fi

exit 0
